import React, { useEffect, useRef } from 'react';
import Header from './components/Header';
import SplitBanner from './components/SplitBanner';
import TheEditSection from './components/TheEditSection';
import MensEditSection from './components/MensEditSection';
import EyewearEditSection from './components/EyewearEditSection';

import banner1 from './assets/images/banner1.jpg';
import banner2 from './assets/images/banner2.jpg';
import banner3 from './assets/images/banner3.jpg';

const womenProducts = [
  {
    id: 1,
    name: 'SINGULAR TOTE PIN (BLACK)',
    price: '325,000 KRW',
    bg: '#d0cec8',
    imgBg: '#b8b5ae',
  },
  {
    id: 2,
    name: 'DRAPE DETAIL SUIT JACKET (IVORY)',
    price: '321,000 KRW',
    bg: '#e8e5de',
    imgBg: '#f0ede6',
  },
  {
    id: 3,
    name: 'OPEN BACK HIGH NECK DRESS (BLACK)',
    price: '295,000 KRW',
    bg: '#d8d5ce',
    imgBg: '#c8c5be',
  },
];

function App() {
  const appRef = useRef(null);

  useEffect(() => {
    const el = appRef.current;
    if (!el) return;

    const sections = Array.from(el.querySelectorAll('section'));
    let isScrolling = false;

    const onWheel = (e) => {
      e.preventDefault();
      if (isScrolling) return;

      const current = sections.reduce((prev, sec) => {
        const rect = sec.getBoundingClientRect();
        return Math.abs(rect.top) < Math.abs(prev.getBoundingClientRect().top) ? sec : prev;
      });

      const idx = sections.indexOf(current);
      const target = e.deltaY > 0 ? sections[idx + 1] : sections[idx - 1];
      if (!target) return;

      isScrolling = true;
      target.scrollIntoView({ behavior: 'smooth' });
      setTimeout(() => { isScrolling = false; }, 900);
    };

    el.addEventListener('wheel', onWheel, { passive: false });
    return () => el.removeEventListener('wheel', onWheel);
  }, []);

  return (
    <div className="app" ref={appRef}>
      <Header />
      <main>
        {/* ── 섹션 1: Womenswear 배너 ── */}
        <SplitBanner
          title="Spring Summer Womenswear Collection"
          theme="light"
          bg="#c8c5bc"
          img={banner1}
          viewStyle="box"
        />

        {/* ── THE EDIT (여성) ── */}
        <TheEditSection products={womenProducts} />

        {/* ── 섹션 2: Menswear 배너 ── */}
        <SplitBanner
          title="Spring Summer Menswear Collection"
          theme="light"
          bg="#2e2c2a"
          img={banner2}
          viewStyle="box"
        />

        {/* ── THE EDIT (남성) ── */}
        <MensEditSection />

        {/* ── 섹션 3: EFFECTOR × RECTO 콜라보 배너 ── */}
        <SplitBanner
          title="EFFECTOR × RECTO"
          theme="light"
          bg="#e8e6e0"
          img={banner3}
          viewStyle="box"
        />

        {/* ── THE EDIT (아이웨어) ── */}
        <EyewearEditSection />
      </main>
    </div>
  );
}

export default App;
